queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEquipment ?child ; p:hasMaintenance_Facilities ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Maintenance_Facilities } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEquipment ?child ; p:hasMaintenance_Facilities ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Maintenance_Facilities } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?type WHERE {
  ?maintenance_facilities_equipment a :Maintenance_Facilities_Equipment .
  ?equipment a :Equipment .
  ?maintenance_facilities_equipment p:hasEquipment ?equipment .
  ?maintenance_facilities a :Maintenance_Facilities .
  ?maintenance_facilities_equipment p:hasMaintenance_Facilities ?maintenance_facilities .
  ?maintenance_facilities p:name ?name .
  ?equipment p:type ?type .
} }
}
